requestIdleCallback((deadline) => {
  while (deadline.timeRemaining() > 0) {
    processNextItem();
  }
}, { timeout: 2000 });

function processNextItem() {
  const items = document.querySelectorAll('.pending');
  if (items.length > 0) {
    items[0].classList.replace('pending', 'done');
  }
}
